15	  // With 0 years (no loyalty), first contract = no follow-up discount but the spec says
16	  // "each item in a quote is treated as a first insurance", so +10% per item applies.
17	  // For pure base premium tests we use multi-step or rely on the integration example math.
18	  // Simpler: test the single-item quote with newcomer 0 years, no curse, low enchantment.
19	
20	  // We'll test via runScenario (the top-level entry point).
21	  it.todo("quote a plain sword for newcomer (0 yrs, 1st contract) → 100 base + 10 first ins + 5 fee = 115 G");
22	  it.todo("quote a plain amulet for newcomer → 60 + 6 + 5 = 71 G");
23	  it.todo("quote a plain staff for newcomer → 80 + 8 + 5 = 93 G");
24	  it.todo("quote a plain potion for newcomer → 40 + 4 + 5 = 49 G");
25	
26	  // Components
27	  it.todo("quote 1 rune for newcomer → 25 + 2.5 first ins = 27.5 → 28 + 5 = 33 G (rounded up in MHPCO favor)");
28	  it.todo("quote 2 runes for newcomer → 50 base + 5 first ins = 55 + 5 = 60 G");
29	
30	  // Block discount
31	  it.todo("3 runes form a block → 60 base premium (block applies)");
32	  it.todo("4 runes → 100 base premium (no block — block requires exactly 3)");
33	  it.todo("7 runes → 175 base premium (one block of 3 = 60, plus 4 individual = 100)");
34	
35	  // Alike-components clarification
36	  it.todo("2 runes + 1 moonstone → 75 base premium (no block: different types)");
37	  it.todo("3 runes + 3 moonstones → 120 base premium (two separate blocks)");
38	
39	  // Modifier thresholds
40	  it.todo("customer with exactly 2 years gets loyalty discount");
41	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
42	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
43	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
44	
45	  // Modifier scope on multi-item policies
46	  it.todo("policy with cursed sword + plain amulet → curse surcharge applies only to sword's base (210 G before fee)");
47	
48	  // Rounding in MHPCO's favor
49	  it.todo("premium 197.5 G → rounded up to 198 G");
50	  it.todo("payout 350.5 G → rounded down to 350 G");
51	
52	  // Integration: Newcomer with a cursed sword
53	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
54	
55	  // Integration: Long-standing customer's second contract
56	  it.todo("3-yr customer's 2nd contract, cursed sword enchantment 7 → 160 G");
57	
58	  // Claim processing — standard reimbursement
59	  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 deductible)");
60	  it.todo("rune damage 200 G → payout 100 G (no special clause, minus deductible)");
61	
62	  // Claim — high enchantment clause
63	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
64	
65	  // Claim — dragon material
66	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full, then deductible)");
67	
68	  // Claim — both clauses (enchantment wins precedence-ordered with 50% then deductible)
69	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G");
70	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G → payout 400 G");
